/* RcpMgmtMapper.getRcpList */ SELECT FN_GET_CODENM('CMN0032', A.SERVICE_TYPE) AS SERVICE_NAME /* 선후불_이름 */ ,A.RES_NO /* 예약번호 */ ,A.SCAN_ID /* 스캔 ID */ ,A.MEMO AS REQUEST_MEMO /* 메모 */ ,B.CSTMR_NAME /* 고객명 */ ,NVL( TRIM(B.CSTMR_FOREIGNER_RRN), '') AS CSTMR_FOREIGNER_RRN /* 외국인 등록번호 */ ,NVL( B.CSTMR_FOREIGNER_NATION, '') AS CSTMR_FOREIGNER_NATION /* 외국인 국적 */ ,TRIM(B.CSTMR_MOBILE_FN) || '-' || trim(B.CSTMR_MOBILE_MN) || '-' || trim(B.CSTMR_MOBILE_RN) AS CSTMR_MOBILE /* 휴대폰번호 */ ,TRIM(B.FATH_MOBILE_FN) || '-' || trim(B.FATH_MOBILE_MN) || '-' || trim(B.FATH_MOBILE_RN) AS FATH_MOBILE /* 안면인증_휴대폰번호 */ ,CASE WHEN OOIM.ORGN_NM IS NOT NULL THEN OOIM.ORGN_NM || '/' || A.CNTPNT_SHOP_ID WHEN A.CNTPNT_SHOP_ID = '1100011741' THEN 'M모바일(직영온라인)' || '/' || A.CNTPNT_SHOP_ID WHEN A.CNTPNT_SHOP_ID = '1100011744' THEN 'M모바일(사내특판)' || '/' || A.CNTPNT_SHOP_ID WHEN A.CNTPNT_SHOP_ID = '1100011745' THEN '총판(㈜프리피아)' || '/' || A.CNTPNT_SHOP_ID ELSE ' ' END AS AGENT_NAME /* 대리점 */ ,(SELECT RATE_NM FROM MSP_RATE_MST WHERE RATE_CD = C.SOC_CODE AND SERVICE_TYPE = 'P' AND ROWNUM = 1) AS SOC_NAME /* 요금제 */ /**************** 프로모션 ID ****************/ ,DECODE(SUBSTR(A.DIS_PRMT_ID,1,1),'F',(SELECT PRMT_NM FROM MSP_DIS_MST WHERE PRMT_ID = A.DIS_PRMT_ID), 'C',(SELECT PRMT_NM FROM MSP_CHRG_PRMT WHERE PRMT_ID = A.DIS_PRMT_ID), '','') AS PRMT_NM ,DECODE(SUBSTR(A.DIS_PRMT_ID,1,1),'F',(SELECT PRMT_ID FROM MSP_DIS_MST WHERE PRMT_ID = A.DIS_PRMT_ID), 'C',(SELECT PRMT_ID FROM MSP_CHRG_PRMT WHERE PRMT_ID = A.DIS_PRMT_ID), '','') AS PRMT_ID ,DECODE(SUBSTR(A.DIS_PRMT_ID,1,1),'F',(SELECT SUM(RM.BASE_AMT) FROM MSP_RATE_MST RM, MSP_DIS_ADD DA WHERE RM.RATE_CD = DA.SOC(+) AND DA.PRMT_ID = DIS_PRMT_ID), 'C',(SELECT SUM(RM.BASE_AMT) FROM MSP_RATE_MST RM, MSP_CHRG_PRMT_ADD DA WHERE RM.RATE_CD = DA.SOC(+) AND DA.PRMT_ID = DIS_PRMT_ID), '','') AS DIS_CNT ,(SELECT RATE_TYPE FROM MSP_RATE_MST WHERE RATE_CD = C.SOC_CODE AND SERVICE_TYPE = 'P' AND ROWNUM = 1) AS PRDT_SCTN_CD ,(SELECT DATA_TYPE FROM MSP_RATE_MST WHERE RATE_CD = C.SOC_CODE AND SERVICE_TYPE = 'P' AND ROWNUM = 1) AS PRDT_SCTN_CD_NAME ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'RCP9001' AND CD_VAL = A.OPER_TYPE) AS OPER_NAME /* 업무구분 */ ,TO_CHAR(A.REQ_IN_DAY,'YYYY-MM-DD') AS REQ_IN_DAY /* 신청일자 */ ,FN_GET_CODENM('RCP0006', A.REQUEST_STATE_CODE) AS REQUEST_STATE_NAME /* 진행상태 */ ,'' AS OPEN_REQ_DATE /* 예약처리일자 */ ,DECODE(A.PSTATE,'00','정상','10','고객취소','20','관리자삭제') AS PSTATE_NAME /* 신청서상태 */ ,A.HUB_ORDER_SEQ /* 알뜰폰 허브 주문번호 */ /****************고객정보****************/ ,A.CSTMR_TYPE /* 고객구분 */ ,A.SERVICE_TYPE /* 서비스구분 */ ,C.SOC_CODE /* 요금제 코드 */ ,A.OPER_TYPE /* 업무구분 */ /*,CSTMR_NAME*/ /*고객명*/ ,B.CSTMR_FOREIGNER_PN /* 여권번호 */ ,TO_CHAR(TO_DATE(B.CSTMR_FOREIGNER_SDATE, 'YYYY-MM-DD'), 'YYYY-MM-DD') AS CSTMR_FOREIGNER_SDATE ,TO_CHAR(TO_DATE(B.CSTMR_FOREIGNER_EDATE, 'YYYY-MM-DD'), 'YYYY-MM-DD') AS CSTMR_FOREIGNER_EDATE ,TO_CHAR(TO_DATE(B.CSTMR_FOREIGNER_BIRTH, 'YYYY-MM-DD'), 'YYYY-MM-DD') AS CSTMR_FOREIGNER_BIRTH ,TO_CHAR(TO_DATE(B.CSTMR_FOREIGNER_BIRTH, 'YYYY-MM-DD'), 'YYMMDD') AS CSTMR_FOREIGNER_BIRTH2 ,CSTMR_FOREIGNER_DOD ,B.CSTMR_JURIDICAL_CNAME /* 법인명 */ ,B.CSTMR_JURIDICAL_RRN /* 법인번호 */ ,SUBSTR(B.CSTMR_JURIDICAL_NUMBER,1,3) AS CSTMR_JURIDICAL_NUMBER1 /* 법인사업자등록번호*/ ,SUBSTR(B.CSTMR_JURIDICAL_NUMBER,4,2) AS CSTMR_JURIDICAL_NUMBER2 /* 법인사업자등록번호*/ ,SUBSTR(B.CSTMR_JURIDICAL_NUMBER,6,5) AS CSTMR_JURIDICAL_NUMBER3 /* 법인사업자등록번호*/ ,B.CSTMR_PRIVATE_CNAME /* 상호명 */ ,SUBSTR(B.CSTMR_PRIVATE_NUMBER,1,3) AS CSTMR_PRIVATE_NUMBER1 /* 개인사업자등록번호*/ ,SUBSTR(B.CSTMR_PRIVATE_NUMBER,4,2) AS CSTMR_PRIVATE_NUMBER2 /* 개인사업자등록번호*/ ,SUBSTR(B.CSTMR_PRIVATE_NUMBER,6,5) AS CSTMR_PRIVATE_NUMBER3 /* 개인사업자등록번호*/ ,B.CSTMR_MAIL ,B.CSTMR_MAIL_RECEIVE_FLAG /* 메일수신여부 */ ,B.CSTMR_ADDR /* 고객정보_주소 */ ,B.CSTMR_ADDR_DTL /* 고객정보_상세주소 */ ,B.CSTMR_BILL_SEND_CODE /* 고객정보_명세서종류*/ ,TRIM(B.CSTMR_TEL_FN) || '-' || TRIM(B.CSTMR_TEL_MN) || '-' || TRIM(B.CSTMR_TEL_RN) AS CSTMR_TEL ,A.ONLINE_AUTH_TYPE /* 온라인_인증방식 */ ,A.ONLINE_AUTH_INFO /* 온라인_인증정보 */ ,DECODE(A.ONLINE_AUTH_TYPE, 'B', CRYPTO_AES256.DEC_AES(A.ONLINE_AUTH_INFO), '') AS DVC_CHG_REC_ID /* 기기변경녹취ID */ ,A.PSTATE /* 신청서_상태 */ ,A.REQUEST_STATE_CODE /* 가입진행_코드 */ ,A.ON_OFF_TYPE /* 온라인오프라인구분*/ ,FN_GET_CODENM('RCP0007', A.ON_OFF_TYPE) AS ON_OFF_NAME /* 모집유형*/ ,'' AS PAPER_INFO /* 서식지정보 */ ,A.PHONE_PAYMENT AS PHONE_PAYMENT /* 휴대폰결제 */ /****************배송정보****************/ ,D.DLVRY_NAME /*배송정보_이름*/ ,TRIM(D.DLVRY_TEL_FN) || '-' || TRIM(D.DLVRY_TEL_MN) || '-' || TRIM(D.DLVRY_TEL_RN) AS DLVRY_TEL ,TRIM(D.DLVRY_MOBILE_FN) || '-' || TRIM(D.DLVRY_MOBILE_MN) || '-' || TRIM(D.DLVRY_MOBILE_RN) AS DLVRY_MOBILE ,D.DLVRY_ADDR /*배송정보_주소*/ ,D.DLVRY_ADDR_DTL /*배송정보_상세주소*/ ,D.DLVRY_MEMO /*배송정보_요청사항*/ /****************요금납부정보****************/ ,A.REQ_PAY_TYPE /*요금납부방법*/ ,E.REQ_BANK /* 신청정보_계좌이체_은행*/ ,E.REQ_ACCOUNT_NUMBER /* 신청정보_계좌이체_계좌번호*/ ,E.REQ_ACCOUNT_NAME /* 신청정보_계좌이체_예금주*/ ,E.REQ_ACCOUNT_RRN ,E.REQ_CARD_COMPANY /*카드사*/ ,E.REQ_CARD_NO ,E.REQ_CARD_MM /*유효기간월*/ ,E.REQ_CARD_YY /*유효기간년*/ ,E.REQ_CARD_NAME /* 신청정보_신용카드_명의자*/ ,E.REQ_CARD_RRN /****************가입신청정보****************/ , A.REQ_BUY_TYPE /*구매유형*/ , A.REQ_MODEL_NAME AS PRDT_CODE /*단말기모델코드*/ , MSPD.PRDT_ID AS PRDT_ID /*단말기ID*/ , A.REQ_WANT_NUMBER /*가입희망번호1*/ , A.REQ_WANT_NUMBER2 /*가입희망번호2*/ , A.REQ_WANT_NUMBER3 /*가입희망번호3*/ , translate(G.REQ_GUIDE_FLAG,'YN','10') AS REQ_GUIDE_FLAG /*신청정보_번호연결서비스_여부*/ , trim(G.REQ_GUIDE_FN) || '-' || trim(G.REQ_GUIDE_MN) || '-' || trim(G.REQ_GUIDE_RN) AS REQ_GUIDE , (case when INSTR(E.REQ_WIRE_TYPE,'AY')>0 then 1 else 0 end) AS REQ_WIRE_TYPE1 /*신청정보_무선데이터_이용_타입*/ , (case when INSTR(E.REQ_WIRE_TYPE,'AN')>0 then 1 else 0 end) AS REQ_WIRE_TYPE2 /*신청정보_무선데이터_이용_타입*/ , (case when INSTR(E.REQ_WIRE_TYPE,'DN')>0 then 1 else 0 end) AS REQ_WIRE_TYPE3 /*신청정보_무선데이터_이용_타입*/ /****************번호이동정보****************/ , trim(G.MOVE_MOBILE_FN) || '-' || trim(G.MOVE_MOBILE_MN) || '-' || trim(G.MOVE_MOBILE_RN) AS MOVE_MOBILE , G.MOVE_COMPANY /*번호이동정보_변경전통신사*/ , G.MOVE_THISMONTH_PAY_TYPE /*번호이동정보_이달사용요금납부방법*/ , G.MOVE_ALLOTMENT_STAT /*번호이동정보_휴대폰_할부금상태*/ , G.MOVE_REFUND_AGREE_FLAG /*번호이동정보_미환급액요금상계동의_여부*/ , G.MOVE_AUTH_TYPE /*번호이동정보_인증유형*/ , G.MOVE_PENALTY /*번호이동정보_위약금*/ /****************법정대리인정보****************/ , H.MINOR_AGENT_NAME /*법인_대리인_성명*/ , H.MINOR_AGENT_RELATION /*미성년자_법정대리인_관계*/ , H.MINOR_AGENT_RRN , trim(H.MINOR_AGENT_TEL_FN) || '-' || trim(H.MINOR_AGENT_TEL_MN) || '-' || trim(H.MINOR_AGENT_TEL_RN) AS MINOR_AGENT_TEL , A.REQUEST_KEY /*가입신청키*/ , F.ADDITION_KEY /*부가서비스키*/ , F.ADDITION_NAME /*부가서비스명*/ , A.CNTPNT_SHOP_ID AS AGENT_CODE , A.CNTPNT_SHOP_ID , B.CSTMR_POST , DECODE(A.CLAUSE_PRI_COLLECT_FLAG,'Y',1,0) AS CLAUSE_PRI_COLLECT_FLAG /*약관_개인정보_수집_동의 */ , DECODE(A.CLAUSE_PRI_OFFER_FLAG,'Y',1,0) AS CLAUSE_PRI_OFFER_FLAG /*약관_개인정보_제공_동의 */ , DECODE(A.CLAUSE_ESS_COLLECT_FLAG,'Y',1,0) AS CLAUSE_ESS_COLLECT_FLAG /*약관_고유식별정보_수집이용제공_동의*/ , DECODE(A.CLAUSE_PRI_TRUST_FLAG,'Y',1,0) AS CLAUSE_PRI_TRUST_FLAG /*약관_개인정보_위탁_동의 */
, A.CLAUSE_PRI_AD_FLAG /*약관_개인정보_광고전송_동의 */ /*20230817 마케팅동의 및 개인정보이용동의 항목 추가*/ , A.PERSONAL_INFO_COLLECT_AGREE /*고객 혜택 제공을 위한 개인정보 수집 및 이용 관련 동의*/ , A.OTHERS_TRNS_AGREE /*혜택 제공을 위한 제3자 제공 동의 : M모바일 */
, A.OTHERS_TRNS_KT_AGREE /*혜택 제공을 위한 제3자 제공 동의 : KT */ , A.OTHERS_AD_RECEIVE_AGREE /*제3자 제공관련 광고 수신 동의 */
, DECODE(A.CLAUSE_CONFIDENCE_FLAG,'Y',1,0) AS CLAUSE_CONFIDENCE_FLAG /*약관_신용정보_이용_동의 */ , A.REQ_USIM_SN /*신청정보_USIM일련변호*/ , A.REQ_PHONE_SN /* 신청정보_휴대폰_일련번호*/ , TRANSLATE(NVL(OTHERS_PAYMENT_AG,'N'), '10','YN') AS OTHERS_PAYMENT_AG /*타인납부*/ , SPC_CODE , D.DLVRY_POST , G.MOVE_AUTH_NUMBER , TRIM(B.CSTMR_NATIVE_RRN) AS CSTMR_NATIVE_RRN ,'가입비 : ' || C.JOIN_PRICE || ' / 유심비 : ' || C.USIM_PRICE || (case when oper_type ='MNP3' then ' / ' || ' 번호이동 시 수수료 800원' end ) AS TRMNL_INFO , TRANSLATE(NVL(REQ_PAY_OTHER_FLAG,'N'), '10','YN') AS REQ_PAY_OTHER_FLAG /*타인납부*/ , I.REQ_AC_TYPE , C.MODEL_INSTALLMENT , C.REAL_MDL_INSTAMT AS REAL_MDL_INSTAMT /* 할부원금 */ , NVL(C.RECYCLE_YN, 'N') AS RECYCLE_YN , C.MODEL_DISCOUNT1 , C.MODEL_DISCOUNT2 AS MODEL_DISCOUNT2 /* 공시지원금 */ , C.MODEL_DISCOUNT3 AS MODEL_DISCOUNT3 /* 대리점지원금 */ , C.JOIN_PRICE , C.USIM_PRICE , C.MODEL_PRICE , C.MODEL_PRICE_VAT , NVL(C.MODEL_PRICE, 0) + NVL(C.MODEL_PRICE_VAT, 0) AS HNDST_AMT /* 출고가VAT포함 */ , NVL(C.MAX_DISCOUNT3, 0) AS MAX_DISCOUNT3 /* 추가지원금(MAX) */ , NVL(C.DC_AMT, 0) AS DC_AMT /* 할인금액 */ , NVL(C.ADD_DC_AMT, 0) AS ADD_DC_AMT /* 추가할인금액 */ , A.REQ_ADDITION_PRICE , NVL(C.MODEL_MONTHLY, 0) AS INST_NOM , NVL(A.SHOP_NM, NVL2(OOIM2.ORGN_NM, OOIM2.ORGN_NM || '/' || OOIM2.ORGN_ID, '')) AS SHOP_NM , DECODE(CUM.USR_NM, NULL, '-', CUM.USR_NM || '/' || CUM.USR_ID) AS USR_NM , I.REQ_AC01_BALANCE , I.REQ_AC02_DAY ,(CASE WHEN I.REQ_AC_TYPE='01' THEN I.REQ_AC01_AMOUNT WHEN I.REQ_AC_TYPE='02' THEN I.REQ_AC02_AMOUNT END ) AS REQ_AC_AMOUNT , A.REQ_MODEL_COLOR , J.TB_CD , J.DLVRY_NO , A.MANAGER_CODE , MSPM.SALE_PLCY_CD , MSPM.SALE_PLCY_NM , A.FAXYN , A.FAXNUM , A.FAXNUM AS FAX_BY_SEARCH , C.MODEL_ID , TO_CHAR(NVL(C.ENGG_MNTH_CNT, 0)) AS AGRM_TRM , MSPD.MNFCT_ID , A.REQ_MODEL_NAME AS REQ_MODEL_NAME , A.REQ_USIM_NAME AS REQ_USIM_NAME , DECODE(A.REC_YN, 'Y', 'Y', 'N') AS REC_YN , A.OPEN_MARKET_REFERER , DECODE(A.NW_BLCK_AGRM_YN, 'Y', 1, 0) AS NW_BLCK_AGRM_YN , DECODE(A.APP_BLCK_AGRM_YN, 'Y', 1, 0) AS APP_BLCK_AGRM_YN , A.APP_CD , DECODE(B.SELF_INQRY_AGRM_YN, 'Y', 1, 0) AS SELF_INQRY_AGRM_YN , B.SELF_CERT_TYPE , B.SELF_ISSU_EXPR_DT , B.SELF_ISSU_NUM , DECODE(H.MINOR_SELF_INQRY_AGRM_YN, 'Y', 1, 0) AS MINOR_SELF_INQRY_AGRM_YN , H.MINOR_SELF_CERT_TYPE , H.MINOR_SELF_ISSU_EXPR_DT , H.MINOR_SELF_ISSU_NUM ,K.DVC_CHG_TYPE ,K.DVC_CHG_RSN_CD ,K.DVC_CHG_RSN_DTL_CD ,C.USIM_PAY_MTHD_CD ,C.JOIN_PAY_MTHD_CD /****************JEJU요금제관련정보****************/ ,DECODE(A.CLAUSE_JEHU_FLAG,'Y',1,0) AS CLAUSE_JEHU_FLAG /*약관_제휴서비스_동의*/ ,B.CSTMR_JEJU_ID ,C.SPRT_TP , NVL(A.PROD_TYPE, '01') AS PROD_TYPE , DECODE(A.CLAUSE_RENTAL_MODEL_CP, 'Y', 1, 0) AS CLAUSE_RENTAL_MODEL_CP , DECODE(A.CLAUSE_RENTAL_MODEL_CP_PR, 'Y', 1, 0) AS CLAUSE_RENTAL_MODEL_CP_PR , DECODE(A.CLAUSE_RENTAL_SERVICE, 'Y', 1, 0) AS CLAUSE_RENTAL_SERVICE , C.RENTAL_BASE_AMT , C.RENTAL_BASE_DC_AMT , C.RENTAL_MODEL_CP_AMT ,DECODE(A.CLAUSE_FINANCE_FLAG,'Y',1,0) AS CLAUSE_FINANCE_FLAG /*금융제휴동의*/ ,A.PROMOTION_CD ,PRMT.PROMOTION_NM ,RTRIM(DECODE(PRMT.BENEFIT_01, 'Y', '추가데이터제공,', '') || DECODE(PRMT.BENEFIT_02, 'Y', '추가기본료할인,', '') || DECODE(PRMT.BENEFIT_03, 'Y', '가입비면제,', '') || DECODE(PRMT.BENEFIT_04, 'Y', '유심비면제,', ''), ',') AS BENEFIT_CMMT ,A.REAL_SHOP_NM /* 실 판매점 */ ,A.USIM_KINDS_CD /* 유심종류 */ ,BNFT.BNFT_KEY /* 고객혜택 KEY */ ,BNFT.BNFT_NAME /* 고객혜택 NAME */ /* SRM18072675707, 단체보험 추가 */ ,A.INSR_CD ,A.CLAUSE_INSURANCE_FLAG ,A.PROD_NM AS DRCT_MNGM_PRDC_NM /* 직영상품명 */ /* 단말보험 */ ,A.INSR_PROD_CD ,A.CLAUSE_INSR_PROD_FLAG ,A.INSR_AUTH_INFO ,B.RECOMMEND_FLAG_CD /* 추천인구분코드 */ ,B.RECOMMEND_INFO /* 추천인정보 */ ,NVL(B.VISA_CD,'') VISA_CD /* VISA 코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'RCP9032' AND CD_VAL = D.DLVRY_TYPE) AS DLVRY_TYPE /* 배송방법*/ /**************** 자급제 정보 ****************/ ,NVL(APD.REQUEST_STATE_CODE ,'') AS PHONE_STATE_CD /* 자급제 폰 배송 상태 코드 */ ,NVL(C.HNDSET_SALE_PRICE ,'') AS HNDSET_SALE_PRICE /* 자급제 폰 출고가 */ ,NVL(C.USE_POINT ,'') AS USE_POINT /* 포인트 */ ,NVL(C.CARD_TOT_DC_AMT ,'') AS CARD_TOT_DC_AMT /* 카드 할인가 */ ,C.HNDSET_SALE_PRICE - C.USE_POINT - C.CARD_TOT_DC_AMT AS LAST_AMT /* 최종구매가 */ ,(SELECT SUBSTR(SUBSCRIBER_NO, 1,3) || '-' || SUBSTR(SUBSCRIBER_NO,4,4) || '-' || SUBSTR(SUBSCRIBER_NO,8,4) FROM MSP_JUO_SUB_INFO WHERE CONTRACT_NUM = C.USE_POINT_SVC_CNTR_NO AND SUB_STATUS != 'C' AND ROWNUM = 1) AS SUBSCRIBER_NO /* 포인트 사용 회선 */ ,MSPDD.PRDT_NM AS SESPLS_PRDT_NM /* 단말 모델 명 */ ,C.SESPLS_PROD_ID AS SESPLS_PROD_ID /* 단말 코드 */ ,(SELECT C.CD_DSC AS COLOR FROM CMN_GRP_CD_MST C WHERE C.GRP_ID = 'CMN0044' AND C.USG_YN = 'Y' AND C.CD_VAL IN (SELECT B.PRDT_COLR_CD FROM CMN_INTM_MDL B WHERE B.RPRS_YN = 'N' AND B.PRDT_ID = C.SESPLS_PROD_ID)) AS SESPLS_PROD_COL /* 단말 색상 */ ,A.EID ,A.IMEI1 ,A.IMEI2 /*ESIM 추가 되면서 단말정보의 고유 식별 번호 추가*/ ,A.ESIM_PHONE_ID AS INTM_MDL_ID /*기기모델ID*/ ,A.REQ_PHONE_SN AS INTM_SRL_NO /*기기모델일련번호*/ ,DECODE(A.UPLOAD_PHONE_SRL_NO, NULL, NULL, (SELECT REQ_MODEL_NAME FROM MCP_UPLOAD_PHONE_INFO@DL_MCP AA WHERE AA.UPLOAD_PHONE_SRL_NO = A.UPLOAD_PHONE_SRL_NO)) AS E_REQ_MODEL_NAME /*기기모델명*/ ,B.PRNTS_CTN /*모회선전화번호*/ ,E.PRNTS_BILL_NO AS BILL_ACNT_NO /*모회선청구번호*/ ,A.PRNTS_CONTRACT_NO /*모회선계약번호*/ ,A.RWD_PROD_CD /*자급제보상서비스코드*/ ,A.CLAUSE_RWD_FLAG /*자급제보상서비스가입동의*/ ,(SELECT KT_INTER_SVC_NO FROM MCP_REQUEST_KT_INTER@DL_MCP WHERE RES_NO = A.RES_NO) AS KT_INTER_SVC_NO ,(SELECT DISTINCT ITEM_ID FROM KIS_KNOTE_SCAN_INFO WHERE REQUEST_KEY = A.REQUEST_KEY AND SCAN_TYPE = 'BEF') AS FRMPAP_ID ,A.AGENT_CODE AS MNGM_AGNC_ID ,A.SHOP_CD AS CNTPNT_CD ,MSPM.PLCY_TYPE_CD /*20240430 위탁온라인 서식지 찾기 위한 판매정책 유형 추출*/ ,OOIM2.TYPE_CD AS CNTPNT_TYPE_CD /*20240430 SHOP_CD 의 조직 유형 */ ,DECODE(A.CLAUSE_SENSI_COLLECT_FLAG, 'Y', 1, 0) AS CLAUSE_SENSI_COLLECT_FLAG /*약관_민감정보_수집_동의*/ ,DECODE(A.CLAUSE_SENSI_OFFER_FLAG, 'Y', 1, 0) AS CLAUSE_SENSI_OFFER_FLAG /*약관_민감정보_제공_동의*/ ,DECODE(A.CLAUSE_PARTNER_OFFER_FLAG,'Y', 1, 0) AS CLAUSE_PARTNER_OFFER_FLAG /*약관_제휴사*/ ,A.JEHU_PROD_TYPE /*약관_제휴처유형*/ ,(SELECT EVNT_CD FROM NMCP_EVENT_CODE_MST@DL_MCP WHERE TO_CHAR(ECP_SEQ) = A.EVNT_CD_PRMT) AS EVNT_CD_PRMT ,(SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'Constant' AND DTL_CD = 'fathUseYn' ) AS FATH_USE_YN ,DECODE(A.FATH_TRG_YN,'Y', 1, 0) AS FATH_TRG_YN ,DECODE(A.CLAUSE_FATH_FLAG,'Y', 1, 0) AS CLAUSE_FATH_FLAG ,A.FATH_TRANSAC_ID ,SUBSTR(FATH_CMPLT_NTFY_DT, 1, 8) AS FATH_CMPLT_NTFY_DT , DECODE(A.COMBINE_SOLO_TYPE, 'Y', 'Y', 'N') AS COMBINE_SOLO_TYPE , DECODE(A.COMBINE_SOLO_FLAG, 'Y', 1, 0) AS COMBINE_SOLO_FLAG FROM MCP_REQUEST@DL_MCP A ,MCP_REQUEST_CSTMR@DL_MCP B ,MCP_REQUEST_SALEINFO@DL_MCP C ,MCP_REQUEST_DLVRY@DL_MCP D ,NMCP_REQUEST_APD_STATE@DL_MCP APD ,MCP_REQUEST_REQ@DL_MCP E ,( SELECT REQUEST_KEY ,LISTAGG(ADDITION_KEY, ',') WITHIN GROUP(ORDER BY ADDITION_KEY) ADDITION_KEY /*부가서비스_키*/ ,LISTAGG(ADDITION_NAME, ',') WITHIN GROUP(ORDER BY ADDITION_NAME) ADDITION_NAME /*부가서비스_키*/ FROM MCP_REQUEST_ADDITION@DL_MCP WHERE REQUEST_KEY = #{requestKey} GROUP BY REQUEST_KEY ) F ,MCP_REQUEST_MOVE@DL_MCP G ,MCP_REQUEST_AGENT@DL_MCP H ,MCP_REQUEST_PAYMENT@DL_MCP I ,MCP_REQUEST_DVC_CHG@DL_MCP K ,ORG_ORGN_INFO_MST OOIM ,ORG_ORGN_INFO_MST OOIM2 ,CMN_USR_MST CUM ,MSP_SALE_PLCY_MST MSPM ,CMN_INTM_MDL MSPD ,CMN_INTM_MDL MSPDD ,(SELECT * FROM (SELECT /*+INDEX_DESC*/ ROW_NUMBER() OVER(PARTITION BY REQUEST_KEY ORDER BY REQUEST_STATE_KEY) ORD,REQUEST_KEY ,TB_CD,DLVRY_NO FROM MCP_REQUEST_STATE@DL_MCP) WHERE ORD=1) J ,MSP_PROMOTION_MST PRMT ,( SELECT REQUEST_KEY ,LISTAGG(CD, ',') WITHIN GROUP(ORDER BY CD) BNFT_KEY ,LISTAGG(CD_NM, ',') WITHIN GROUP(ORDER BY CD_NM) BNFT_NAME FROM MCP_REQUEST_BENEFIT@DL_MCP WHERE REQUEST_KEY = #{requestKey} GROUP BY REQUEST_KEY ) BNFT WHERE A.REQUEST_KEY = B.REQUEST_KEY(+) AND A.REQUEST_KEY = C.REQUEST_KEY(+) AND A.REQUEST_KEY = D.REQUEST_KEY(+) AND A.REQUEST_KEY = E.REQUEST_KEY(+) AND A.REQUEST_KEY = F.REQUEST_KEY(+) AND A.REQUEST_KEY = G.REQUEST_KEY(+) AND A.REQUEST_KEY = H.REQUEST_KEY(+) AND A.REQUEST_KEY = I.REQUEST_KEY(+) AND A.REQUEST_KEY = J.REQUEST_KEY(+) AND A.REQUEST_KEY = K.REQUEST_KEY(+) AND A.REQUEST_KEY = APD.REQUEST_KEY(+) AND A.REQUEST_KEY = BNFT.REQUEST_KEY(+) AND A.CNTPNT_SHOP_ID = OOIM.ORGN_ID(+) AND A.SHOP_CD = OOIM2.ORGN_ID(+) AND A.SHOP_USM_ID = CUM.USR_ID(+) AND C.MODEL_SALE_POLICY_CODE = MSPM.SALE_PLCY_CD(+) AND C.MODEL_ID = MSPD.PRDT_ID(+) AND C.SESPLS_PROD_ID = MSPDD.PRDT_ID(+) AND A.PROMOTION_CD = PRMT.PROMOTION_CD(+) AND A.REQUEST_KEY = #{requestKey}

SELECT /* RcpMgmtMapper.getRcpCommon */ VALUE AS VALUE /* 코드 값 */ , TEXT AS TEXT /* 코드 내용 */ FROM (
SELECT 'RATE', VALUE, TEXT, ROW_NUMBER () OVER (ORDER BY DATA_TYPE DESC, TEXT, RATE_TYPE) ROW_NUM FROM ( SELECT RATE.RATE_CD AS VALUE, RATE.RATE_NM AS TEXT, RATE.DATA_TYPE, RATE.RATE_TYPE FROM MSP_RATE_MST RATE WHERE SERVICE_TYPE = 'P' /* 상품 */ /* MSP_RATE_MST 날짜 */ AND TO_CHAR(SYSDATE, 'YYYYMMDD')
AND REPLACE(#{reqInDay}, '-', '')
BETWEEN RATE.APPL_STRT_DT AND RATE.APPL_END_DT
AND RATE.PAY_CL_CD = #{serviceType} /* 서비스구분, 필수 */
) ORDER BY 4
SELECT 'PRDT', VALUE, TEXT, ROW_NUMBER () OVER (ORDER BY TEXT ) ROW_NUM FROM( SELECT PRDT_ID AS VALUE, PRDT_NM || '['|| PRDT_CODE || ']' AS TEXT FROM CMN_INTM_MDL CIM WHERE CIM.RPRS_YN = 'Y'
AND TO_CHAR(SYSDATE, 'YYYYMMDD')
AND REPLACE(#{reqInDay}, '-', '')
BETWEEN NVL(CIM.PRDT_LNCH_DT,
TO_CHAR(SYSDATE, 'YYYYMMDD')
REPLACE(#{reqInDay}, '-', '')
) AND CIM.PRDT_DT
AND CIM.PRDT_TYPE_CD = DECODE(#{reqBuyType}, 'MM', '01', 'UU', '02') /* 단말/USIM */
AND CIM.MNFCT_ID = #{mnfctId}
AND CIM.PRDT_IND_CD IN ('10','11')
AND CIM.PRDT_IND_CD = #{prdtIndCd}
AND CIM.PRDT_IND_CD NOT IN ('10','11')
) ORDER BY 4
SELECT 'COLOR', VALUE, TEXT, ROW_NUMBER () OVER (ORDER BY TEXT ) ROW_NUM FROM ( SELECT C.CD_VAL AS VALUE ,C.CD_DSC AS TEXT FROM CMN_GRP_CD_MST C WHERE C.GRP_ID = 'CMN0044' AND C.USG_YN = 'Y'
AND C.CD_VAL IN ( SELECT B.PRDT_COLR_CD FROM CMN_INTM_MDL B WHERE B.RPRS_YN = 'N'
AND B.RPRS_PRDT_ID = #{prdtId}
AND B.MNFCT_ID = #{mnfctId}
)
) ORDER BY 4
SELECT 'MNFCT', VALUE, TEXT, ROW_NUMBER () OVER (ORDER BY TEXT ) ROW_NUM FROM ( SELECT MNFCT_ID AS VALUE, MNFCT_NM AS TEXT FROM ORG_MNFCT_MST ) ORDER BY 4
SELECT 'COMM', CD_VAL AS VALUE, CD_DSC AS TEXT, ROW_NUMBER () OVER (ORDER BY CD_DSC) ROW_NUM FROM CMN_GRP_CD_MST WHERE GRP_ID = #{cdId} AND USG_YN='Y' ORDER BY 4, 2
SELECT SUBSTR( CODE_SYS, 1, 3 ) , DECODE( CODE_SYS,'EML', CODE_NAME, CODE) AS VALUE, CODE_NAME AS TEXT, ORD FROM MCP_CODE@DL_MCP WHERE INSTR(#{grpId},CODE_SYS)>0
AND CODE = #{cdNm}
ORDER BY 4, 1
SELECT 'PRDT', VALUE, TEXT, ROW_NUMBER () OVER (ORDER BY TEXT ) ROW_NUM FROM( SELECT PRDT_ID AS VALUE, PRDT_NM || '['|| PRDT_CODE || ']' AS TEXT FROM CMN_INTM_MDL CIM WHERE CIM.RPRS_YN = 'Y'
AND CIM.PRDT_TYPE_CD = DECODE(#{reqBuyType}, 'MM', '01', 'UU', '02') /* 단말/USIM */
AND CIM.MNFCT_ID = #{mnfctId}
) ORDER BY 4
)

SELECT /* RcpMgmtMapper.getRcpCommon */ VALUE AS VALUE /* 코드 값 */ , TEXT AS TEXT /* 코드 내용 */ FROM (
SELECT 'PRDT', VALUE, TEXT, ROW_NUMBER () OVER (ORDER BY TEXT ) ROW_NUM FROM( SELECT PRDT_ID AS VALUE, PRDT_NM || '['|| PRDT_CODE || ']' AS TEXT FROM CMN_INTM_MDL CIM WHERE CIM.RPRS_YN = 'Y'
AND TO_CHAR(SYSDATE, 'YYYYMMDD')
AND REPLACE(#{reqInDay}, '-', '')
BETWEEN NVL(CIM.PRDT_LNCH_DT,
TO_CHAR(SYSDATE, 'YYYYMMDD')
REPLACE(#{reqInDay}, '-', '')
) AND CIM.PRDT_DT
AND CIM.PRDT_TYPE_CD = DECODE(#{reqBuyType}, 'MM', '01', 'UU', '02') /* 단말/USIM */
AND CIM.MNFCT_ID = #{mnfctId}
) ORDER BY 4
SELECT 'PRDT', VALUE, TEXT, ROW_NUMBER () OVER (ORDER BY TEXT ) ROW_NUM FROM( SELECT PRDT_ID AS VALUE, PRDT_NM || '['|| PRDT_CODE || ']' AS TEXT FROM CMN_INTM_MDL CIM WHERE CIM.RPRS_YN = 'Y'
AND CIM.PRDT_TYPE_CD = DECODE(#{reqBuyType}, 'MM', '01', 'UU', '02') /* 단말/USIM */
AND CIM.MNFCT_ID = #{mnfctId}
) ORDER BY 4
)

mapper.insert:
/* RcpMgmtMapper.insertRcpRequest */ INSERT INTO MCP_REQUEST@DL_MCP ( REQUEST_KEY, MANAGER_CODE, AGENT_CODE, SERVICE_TYPE, OPER_TYPE, CSTMR_TYPE, RES_CODE, RES_MSG, RES_NO, CLAUSE_PRI_COLLECT_FLAG, CLAUSE_PRI_OFFER_FLAG, CLAUSE_ESS_COLLECT_FLAG,
CLAUSE_PRI_AD_FLAG, CLAUSE_CONFIDENCE_FLAG, ONLINE_AUTH_TYPE, ONLINE_AUTH_INFO, PSTATE, REQUEST_STATE_CODE, OPEN_NO, FILE01, FILE01_MASK, FAXYN, FAXNUM, SCAN_ID, ON_OFF_TYPE, RIP, SYS_RDATE, REQ_WANT_NUMBER, REQ_WANT_NUMBER2, REQ_WANT_NUMBER3, REQ_BUY_TYPE, REQ_MODEL_NAME, REQ_MODEL_COLOR, REQ_PHONE_SN, REQ_USIM_SN, REQ_PAY_TYPE, REQ_ADDITION, SHOP_CD, REQ_IN_DAY, PHONE_PAYMENT, REQ_ADDITION_PRICE, SPC_CODE, CNTPNT_SHOP_ID,SHOP_USM_ID, MEMO,DIS_PRMT_ID,NW_BLCK_AGRM_YN, APP_BLCK_AGRM_YN, REQ_USIM_NAME, APP_CD, CLAUSE_JEHU_FLAG, SHOP_NM ,PROD_TYPE, CONTRACT_NUM, CLAUSE_FINANCE_FLAG, CLAUSE_RENTAL_MODEL_CP, CLAUSE_RENTAL_MODEL_CP_PR, CLAUSE_RENTAL_SERVICE, RVISN_ID, RVISN_DTTM, PROMOTION_CD, REAL_SHOP_NM, USIM_KINDS_CD /* SRM18072675707, 단체보험 추가 */ , INSR_CD, CLAUSE_INSURANCE_FLAG /* 단말보험 */ , INSR_PROD_CD, CLAUSE_INSR_PROD_FLAG /* esim 정보 */ , EID, IMEI1, IMEI2 , ESIM_PHONE_ID /* eSIM Watch */ , PRNTS_CONTRACT_NO /*개인정보 수집이용 동의(혜택), 제 3자 제공 동의 추가*/ ,PERSONAL_INFO_COLLECT_AGREE, OTHERS_TRNS_AGREE ,OTHERS_TRNS_KT_AGREE, OTHERS_AD_RECEIVE_AGREE , HUB_ORDER_SEQ /* 민감정보 수집 동의 , 민감정보 제공 동의 추가 2025-01-07 */ , CLAUSE_SENSI_COLLECT_FLAG, CLAUSE_SENSI_OFFER_FLAG , JEHU_PROD_TYPE , CLAUSE_PARTNER_OFFER_FLAG , CLAUSE_FATH_FLAG , COMBINE_SOLO_TYPE , COMBINE_SOLO_FLAG ) VALUES ( DECODE(#{requestKey }, 'null', '',#{requestKey }), DECODE(#{managerCode }, 'null', '',#{managerCode }), DECODE(#{agentCode }, 'null', '',#{agentCode }), DECODE(#{serviceType }, 'null', '',#{serviceType }), DECODE(#{operType }, 'null', '',#{operType }), DECODE(#{cstmrType }, 'null', '',#{cstmrType }), DECODE(#{resCode }, 'null', '',#{resCode }), DECODE(#{resMsg }, 'null', '',#{resMsg }), DECODE(#{resNo }, 'null', '',#{resNo }), DECODE(#{clausePriCollectFlag },'0', 'N',#{clausePriCollectFlag }), DECODE(#{clausePriOfferFlag }, '0', 'N',#{clausePriOfferFlag }), DECODE(#{clauseEssCollectFlag },'0', 'N',#{clauseEssCollectFlag }),
DECODE(#{clausePriAdFlag }, '0', 'N',#{clausePriAdFlag }), DECODE(#{clauseConfidenceFlag },'0', 'N',#{clauseConfidenceFlag }), DECODE(#{onlineAuthType }, 'null', '',#{onlineAuthType }), DECODE(#{onlineAuthInfo }, 'null', '',#{onlineAuthInfo }), DECODE(#{pstate }, 'null', '',#{pstate }), DECODE(#{requestStateCode }, 'null', '',#{requestStateCode }), DECODE(#{openNo }, 'null', '',#{openNo }), DECODE(#{file01 }, 'null', '',#{file01 }), DECODE(#{file01Mask }, 'null', '',#{file01Mask }), DECODE(#{faxyn }, 'null', '',#{faxyn }), DECODE(#{faxnum }, 'null', '',#{faxnum }), DECODE(#{scanId }, 'null', '',#{scanId }), DECODE(#{onOffType }, 'null', '',#{onOffType }), DECODE(#{rip }, 'null', '',#{rip }), SYSDATE, DECODE(#{reqWantNumber }, 'null', '',#{reqWantNumber }), DECODE(#{reqWantNumber2 }, 'null', '',#{reqWantNumber2 }), DECODE(#{reqWantNumber3 }, 'null', '',#{reqWantNumber3 }), DECODE(#{reqBuyType }, 'null', '',#{reqBuyType }), DECODE(#{reqModelName }, 'null', '',#{reqModelName }), DECODE(#{reqModelColor }, 'null', '',#{reqModelColor }), DECODE(#{reqPhoneSn }, 'null', '',#{reqPhoneSn }), DECODE(#{reqUsimSn }, 'null', '',#{reqUsimSn }), DECODE(#{reqPayType }, 'null', '',#{reqPayType }), DECODE(#{additionName }, 'null', '',#{additionName }), DECODE(#{shopCd }, 'null', '',#{shopCd }), SYSDATE, DECODE(#{phonePayment }, 'null', '',#{phonePayment }), DECODE(#{additionPrice }, 'null', '',#{additionPrice }), DECODE(#{spcCode }, 'null', '',#{spcCode }), DECODE(#{cntpntShopId}, 'null', '',#{cntpntShopId}), DECODE(#{shopUsmId}, 'null', '',#{shopUsmId}), DECODE(#{requestMemo}, 'null', '',#{requestMemo}), DECODE(#{disPrmtId}, 'null', '',#{disPrmtId}), DECODE(#{nwBlckAgrmYn}, '0', 'N', #{nwBlckAgrmYn}), DECODE(#{appBlckAgrmYn}, '0', 'N', #{appBlckAgrmYn}), DECODE(#{reqUsimName}, 'null', '', #{reqUsimName}), #{appCd}, DECODE(#{clauseJehuFlag}, '0', 'N', #{clauseJehuFlag}), DECODE(#{shopNm}, 'null', '', DECODE((TRANSLATE(#{shopNm}, '/', '')), NULL, '', #{shopNm})), DECODE(#{prodType}, 'n