WITH TT AS(
	SELECT
		DISTINCT MSSM.PRDT_ID, MSPM.SALE_PLCY_CD, MSSM.ORGN_ID, MSSM.OLD_YN
	FROM MSP_SALE_PLCY_MST MSPM, MSP_SALE_SUBSD_MST MSSM
	WHERE MSPM.SALE_PLCY_CD = MSSM.SALE_PLCY_CD


			AND MSSM.SALE_PLCY_CD = #{salePlcyCd}


			AND MSSM.ORGN_ID = #{orgnId}


)
