/* RcpMgmtMapper.checkPhoneSN */ SELECT B.RPRS_PRDT_ID AS PRDT_ID , A.PRDT_SRL_NUM , CASE WHEN SVC_CT_NUM IS NULL OR A.SVC_CT_NUM = '000000000' THEN 0 ELSE 1 END SVC_CT_NUM , B.PRDT_CODE , B.PRDT_COLR_CD , COUNT(PRDT_SRL_NUM) CNT FROM LGS_PRDT_SRL_MST A , CMN_INTM_MDL B WHERE 1 = 1
AND A.PRDT_SRL_NUM = #{reqPhoneSn}
AND A.RPRS_PRDT_ID = #{prdtId}
AND B.PRDT_COLR_CD = #{reqModelColor}
AND A.ORGN_ID = #{cntpntShopId}
AND A.LOGIS_PROC_STAT_CD IN ( SELECT CD_VAL FROM CMN_GRP_CD_MST WHERE GRP_ID = 'LGS1000' AND ETC3 = 'AG' AND ETC5 = 'Z11' ) AND A.PRDT_ID = B.PRDT_ID GROUP BY B.RPRS_PRDT_ID, A.PRDT_SRL_NUM, A.SVC_CT_NUM, B.PRDT_CODE, B.PRDT_COLR_CD UNION ALL SELECT B.RPRS_PRDT_ID AS PRDT_ID , A.PRDT_SRL_NUM , CASE WHEN A.SVC_CT_NUM IS NULL OR A.SVC_CT_NUM = '000000000' THEN 0 ELSE 1 END SVC_CT_NUM , B.PRDT_CODE , B.PRDT_COLR_CD , COUNT(PRDT_SRL_NUM) CNT FROM LGS_OTCP_SRL_MST A , CMN_INTM_MDL B WHERE 1 = 1
AND A.PRDT_SRL_NUM = #{reqPhoneSn}
AND A.RPRS_PRDT_ID = #{prdtId}
AND B.PRDT_COLR_CD = #{reqModelColor}
AND A.IN_ORGN_ID = #{cntpntShopId}
AND A.LOGIS_PROC_STAT_CD IN ( SELECT CD_VAL FROM CMN_GRP_CD_MST WHERE GRP_ID = 'LGS1000' AND ETC3 = 'AG' AND ETC5 = 'Z11' ) AND A.PRDT_ID = B.PRDT_ID GROUP BY B.RPRS_PRDT_ID, A.PRDT_SRL_NUM, A.SVC_CT_NUM, B.PRDT_CODE, B.PRDT_COLR_CD

