mapper.sql:
SELECT A.REQUEST_KEY , A.RES_NO , A.CNTPNT_SHOP_ID , FN_GET_ORGNM(A.CNTPNT_SHOP_ID) AS AGENT_NAME , A.REQ_BUY_TYPE , FN_GET_CODENM('RCP9004', A.REQ_BUY_TYPE) AS REQ_BUY_NM , A.OPER_TYPE , FN_GET_CODENM('RCP9001', A.OPER_TYPE) AS OPER_NAME , A.REQUEST_STATE_CODE , FN_GET_CODENM('RCP0006', A.REQUEST_STATE_CODE) REQUEST_STATE_NAME , A.SERVICE_TYPE , FN_GET_CODENM('RCP0013', A.SERVICE_TYPE) AS SERVICE_NAME , TO_CHAR(A.REQ_IN_DAY, 'YYYY-MM-DD') REQ_IN_DT , A.ON_OFF_TYPE , FN_GET_CODENM('RCP0007', NVL(A.ON_OFF_TYPE, '0')) ON_OFF_NM , A.OPEN_MARKET_REFERER , A.SPC_CODE , C.SOC_CODE , FN_GET_RATENM(C.SOC_CODE) AS SOC_NAME , B.CSTMR_NAME AS CSTMR_NAME2 , B.CSTMR_NATIVE_RRN , B.CSTMR_FOREIGNER_RRN , B.CSTMR_MOBILE_FN || B.CSTMR_MOBILE_MN || B.CSTMR_MOBILE_RN AS CSTMR_MOBILE , CASE WHEN A.REQUEST_STATE_CODE IN ('08', '09', '10') THEN TO_CHAR(A.SYS_RDATE, 'YYYYMMDDHH24MISS') ELSE '' END DLV_DTTM , CASE WHEN A.REQUEST_STATE_CODE IN ('08', '09') THEN TO_CHAR(A.SYS_RDATE, 'HH24:MI:SS') ELSE '' END SET_DTTM , TO_CHAR(A.SYS_RDATE, 'YYYYMMDDHH24MISS') AS SYS_RDATE , FN_GET_USRNM(A.RVISN_ID) AS RVISN_NM , TO_CHAR(A.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS RVISN_DTTM FROM MCP_REQUEST@DL_MCP A , MCP_REQUEST_CSTMR@DL_MCP B , MCP_REQUEST_SALEINFO@DL_MCP C WHERE 1 = 1 AND A.REQUEST_KEY = B.REQUEST_KEY AND A.REQUEST_KEY = C.REQUEST_KEY AND A.REQ_IN_DAY BETWEEN TO_DATE(#{strtDt} || '000000', 'YYYYMMDDHH24MISS') AND TO_DATE(#{endDt} || '235959', 'YYYYMMDDHH24MISS') AND A.PSTATE = '00' AND (A.USIM_KINDS_CD != '09' OR A.USIM_KINDS_CD IS NULL) AND A.CNTPNT_SHOP_ID = #{agntCd}
AND A.SERVICE_TYPE = #{serviceType}
AND A.REQUEST_STATE_CODE = #{requestStateCode}
AND A.REQ_BUY_TYPE = #{reqBuyType}
AND A.OPER_TYPE = #{pOperType} /*신청유형-신규가입/번호이동정보/기기변경정보*/
AND B.CSTMR_NAME LIKE #{searchVal} || '%'
AND A.CONTRACT_NUM = #{searchVal}
AND NVL(B.CSTMR_MOBILE_FN || B.CSTMR_MOBILE_MN || B.CSTMR_TEL_RN, B.CSTMR_TEL_FN || B.CSTMR_TEL_MN || B.CSTMR_MOBILE_RN) LIKE TRANSLATE(#{searchVal},'1234567890-','1234567890')||'%'
AND A.REQ_PHONE_SN LIKE '%' || #{searchVal} || '%'
AND A.RES_NO LIKE '%' || #{searchVal} || '%'
AND A.USIM_KINDS_CD = #{usimKindsCd}
ORDER BY A.REQUEST_KEY DESC

