mapper.sql:
SELECT A.REQUEST_KEY , A.RES_NO , A.CNTPNT_SHOP_ID , ORG.ORGN_NM AS AGENT_NAME , A.REQ_BUY_TYPE , DECODE(A.REQ_BUY_TYPE, 'MM', '단말구매', '유심단독') REQ_BUY_NM , A.OPER_TYPE , DECODE(A.OPER_TYPE, 'MNP3', '번호이동', 'NAC3', '신규가입', 'HCN3', '기기변경' ) AS OPER_NAME , A.REQUEST_STATE_CODE , FN_GET_CODENM('RCP0006', A.REQUEST_STATE_CODE) REQUEST_STATE_NAME , A.SERVICE_TYPE , DECODE(A.SERVICE_TYPE, 'PO', '후불', '선불') SERVICE_NAME , TO_CHAR(A.REQ_IN_DAY, 'YYYY-MM-DD') REQ_IN_DT , A.ON_OFF_TYPE , FN_GET_CODENM('RCP0007', NVL(A.ON_OFF_TYPE, '0')) ON_OFF_NM , A.OPEN_MARKET_REFERER , MDL.MNFCT_ID , DECODE(A.REQ_BUY_TYPE, 'MM', ( SELECT MNFCT_NM FROM ORG_MNFCT_MST WHERE MNFCT_ID = MDL.MNFCT_ID ), '') AS MNFCT_NM , DECODE(A.REQ_BUY_TYPE, 'MM', MDL.RPRS_PRDT_ID, '') AS PRDT_ID , DECODE(A.REQ_BUY_TYPE, 'MM', MDL.PRDT_CODE, '') AS PRDT_CODE , DECODE(A.REQ_BUY_TYPE, 'MM', MDL.PRDT_NM, '') AS MODEL_NAME , DECODE(A.REQ_BUY_TYPE, 'MM', NVL(FN_GET_CODENM ('CMN0044', MDL.PRDT_COLR_CD), A.REQ_MODEL_COLOR), '') AS REQ_MODEL_COLOR , A.REQ_PHONE_SN , A.REQ_PHONE_SN AS REQ_PHONE_SN_MASK , ( SELECT MNFCT_NM FROM ORG_MNFCT_MST WHERE MNFCT_ID = USIM.MNFCT_ID ) AS USIM_MNFCT_NM , USIM.PRDT_CODE AS USIM_ID , USIM.PRDT_NM AS USIM_NAME , A.REQ_USIM_SN , A.REQ_USIM_SN AS REQ_USIM_SN_MASK , A.SPC_CODE , A.MEMO AS REQUEST_MEMO , C.SOC_CODE , RATE.RATE_NM AS SOC_NAME , A.CSTMR_TYPE , B.CSTMR_NAME , B.CSTMR_NAME AS CSTMR_NAME_MASK , B.CSTMR_NATIVE_RRN , B.CSTMR_FOREIGNER_RRN , B.CSTMR_PRIVATE_CNAME , B.CSTMR_PRIVATE_NUMBER , B.CSTMR_JURIDICAL_CNAME , B.CSTMR_JURIDICAL_RRN , B.CSTMR_TEL_FN , B.CSTMR_TEL_MN , B.CSTMR_TEL_RN , B.CSTMR_TEL_FN || B.CSTMR_TEL_MN || B.CSTMR_TEL_RN AS CSTMR_TEL , B.CSTMR_MOBILE_FN , B.CSTMR_MOBILE_MN , B.CSTMR_MOBILE_RN , NVL(B.CSTMR_MOBILE_FN || B.CSTMR_MOBILE_MN || B.CSTMR_MOBILE_RN, B.CSTMR_TEL_FN || B.CSTMR_TEL_MN || B.CSTMR_TEL_RN) AS CSTMR_MOBILE , B.CSTMR_POST , B.CSTMR_ADDR , B.CSTMR_ADDR_DTL , B.CSTMR_MAIL , D.DLVRY_NAME , D.DLVRY_TEL_FN , D.DLVRY_TEL_MN , D.DLVRY_TEL_RN , D.DLVRY_MOBILE_FN , D.DLVRY_MOBILE_MN , D.DLVRY_MOBILE_RN , D.DLVRY_MOBILE_FN || D.DLVRY_MOBILE_MN || D.DLVRY_MOBILE_RN AS DLVRY_MOBILE , D.DLVRY_POST , D.DLVRY_ADDR , D.DLVRY_ADDR_DTL , D.DLVRY_ADDR || ' ' || D.DLVRY_ADDR_DTL AS FULL_DLVRY_ADDR , D.DLVRY_ADDR_BJD , D.DLVRY_MEMO , E.TB_CD , E.DLVRY_NO , A.PROD_TYPE , DECODE(A.PROD_TYPE, '02', '렌탈', '일반') AS PROD_TYPE_NM , DECODE(A.CLAUSE_RENTAL_MODEL_CP, 'Y', 1, 0) AS CLAUSE_RENTAL_MODEL_CP , DECODE(A.CLAUSE_RENTAL_MODEL_CP_PR, 'Y', 1, 0) AS CLAUSE_RENTAL_MODEL_CP_PR , DECODE(A.CLAUSE_RENTAL_SERVICE, 'Y', 1, 0) AS CLAUSE_RENTAL_SERVICE , C.RENTAL_BASE_AMT , C.RENTAL_BASE_DC_AMT , C.RENTAL_MODEL_CP_AMT , TO_CHAR(A.SYS_RDATE, 'YYYYMMDDHH24MISS') AS SYS_RDATE , (SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = A.RVISN_ID) AS RVISN_NM , TO_CHAR(A.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS RVISN_DTTM FROM MCP_REQUEST@DL_MCP A , MCP_REQUEST_CSTMR@DL_MCP B , MCP_REQUEST_SALEINFO@DL_MCP C , MCP_REQUEST_DLVRY@DL_MCP D , MCP_REQUEST_STATE@DL_MCP E , CMN_INTM_MDL MDL , CMN_INTM_MDL USIM , ORG_ORGN_INFO_MST ORG , MSP_RATE_MST RATE WHERE A.REQUEST_KEY = B.REQUEST_KEY AND A.REQUEST_KEY = C.REQUEST_KEY AND A.REQUEST_KEY = D.REQUEST_KEY AND A.REQUEST_KEY = E.REQUEST_KEY AND C.SOC_CODE = RATE.RATE_CD AND RATE.SERVICE_TYPE = 'P' AND TO_CHAR(A.REQ_IN_DAY, 'YYYYMMDD') BETWEEN RATE.APPL_STRT_DT AND RATE.APPL_END_DT AND C.MODEL_ID = MDL.PRDT_ID(+) AND A.REQ_USIM_NAME = USIM.PRDT_CODE(+) AND A.CNTPNT_SHOP_ID = ORG.ORGN_ID AND A.PSTATE = '00' AND A.PROD_TYPE = '02' AND TO_CHAR(A.REQ_IN_DAY, 'YYYYMMDD') BETWEEN #{strtDt} AND #{endDt}
AND A.CNTPNT_SHOP_ID = #{orgnId}
AND A.SERVICE_TYPE = #{serviceType}
AND A.REQUEST_STATE_CODE = #{requestStateCode}
AND A.REQ_BUY_TYPE = #{reqBuyType}
AND B.CSTMR_NAME LIKE '%' || #{searchVal} || '%'
AND A.CONTRACT_NUM = #{searchVal}
AND B.CSTMR_MOBILE_FN || B.CSTMR_MOBILE_MN || B.CSTMR_MOBILE_RN like '%'||translate(#{searchVal},'1234567890-','1234567890')||'%'
AND A.REQ_PHONE_SN LIKE '%' || #{searchVal} || '%'
AND A.RES_NO LIKE '%' || #{searchVal} || '%'
ORDER BY A.RES_NO DESC

